import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as d,e as c}from"./app-be253e4c.js";const a={},r=c('<h1 id="原型模式" tabindex="-1"><a class="header-anchor" href="#原型模式" aria-hidden="true">#</a> 原型模式</h1><p>原型模式<code>Prototype Pattern</code>用原型实例指向创建对象的类，使用于创建新的对象的类的共享原型的属性与方法。</p><h2 id="基本介绍" tabindex="-1"><a class="header-anchor" href="#基本介绍" aria-hidden="true">#</a> 基本介绍</h2><p>在<code>JavaScript</code>中可以利用其特有的原型继承特性去实现创建对象的方式，也就是创建的一个对象作为另外一个对象的<code>prototype</code> 属性值，原型对象本身就是有效地利用了每个构造器创建的对象，其将实例之间相同的属性和方法提取成共有的属性和方法，而这些属性与方法都可以被实例共享。 在<code>Java</code>中通常是用原型实例指定创建对象的种类，并通过拷贝这些原型创建新的对象，即通过一个抽象类实现<code>Cloneable</code> 接口以及重写<code>Object</code>类中的<code>clone</code>方法，之后使用子类继承此抽象类并在一个缓存类中使用集合类例如<code>HashTable</code> 进行存储，当需要类时便可以找到<code>HashTable</code>中该类通过<code>clone</code>实现得到一个新的子类，使用原型模式创建对象比直接<code>new</code> 一个对象在性能上要好的多，因为<code>Object</code>类的<code>clone</code> 方法是一个本地方法，它直接操作内存中的二进制流，特别是复制大对象时，性能的差别非常明显。使用原型模式的另一个好处是简化对象的创建，使得创建对象就像我们在编辑文档时的复制粘贴一样简单，所以在需要重复地创建相似对象时可以考虑使用原型模式，此外深拷贝与浅拷贝问题中，会发生深拷贝的有<code>Java</code> 中的<code>8</code>种基本类型以及他们的封装类型以及<code>String</code>类型，其余的都是浅拷贝。</p><h3 id="优点" tabindex="-1"><a class="header-anchor" href="#优点" aria-hidden="true">#</a> 优点</h3><ul><li>提高性能。</li><li>避免构造函数的约束。</li></ul><h3 id="缺点" tabindex="-1"><a class="header-anchor" href="#缺点" aria-hidden="true">#</a> 缺点</h3><ul><li>在原型中需要对所有类的功能进行考虑。</li><li>创建对象不会调用类的构造方法。</li></ul><h2 id="代码实现" tabindex="-1"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2>',9),t=[r];function i(h,n){return o(),d("div",null,t)}const p=e(a,[["render",i],["__file","prototype-mode.html.vue"]]);export{p as default};
